// Validate secret and extract params
const data = $input.first().json;
const body = data.body || data;

const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');
const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

const content_id = body.content_id;
if (!content_id) throw new Error('Missing required field: content_id');

return [{ json: { content_id } }];

// Read content row + merge brand data
const { content_id } = $input.first().json;

const baseUrl = $env.NOCODB_BASE_URL;
const token = $env.NOCODB_API_TOKEN;
let baseId = $env.NOCODB_CF_BASE_ID || '';
let contentsId = $env.NOCODB_CONTENTS_TABLE_ID || '';
let brandsId = $env.NOCODB_BRANDS_TABLE_ID || '';

// Resolve table IDs via meta API if not set
if (!baseId || !contentsId || !brandsId) {
  const basesResp = await $http.request({
    method: 'GET',
    url: `${baseUrl}/api/v2/meta/bases/`,
    headers: { 'xc-token': token }
  });
  const base = (basesResp.list || []).find(b => b.title === 'content-factory');
  if (!base) throw new Error('NocoDB base content-factory not found');
  baseId = base.id;

  const tablesResp = await $http.request({
    method: 'GET',
    url: `${baseUrl}/api/v2/meta/bases/${baseId}/tables`,
    headers: { 'xc-token': token }
  });
  const tables = tablesResp.list || [];
  contentsId = contentsId || (tables.find(t => t.title === 'contents') || {}).id;
  brandsId = brandsId || (tables.find(t => t.title === 'brands') || {}).id;
  if (!contentsId) throw new Error('NocoDB table contents not found');
}

// Fetch content record by Id
const contentResp = await $http.request({
  method: 'GET',
  url: `${baseUrl}/api/v2/meta/bases/${baseId}/tables/${contentsId}/records`,
  headers: { 'xc-token': token },
  qs: { where: `(Id,eq,${content_id})`, limit: 1 }
});

const contentRow = (contentResp.list || [])[0];
if (!contentRow) throw new Error(`Content ${content_id} not found`);

// Build result with content_id
const result = { ...contentRow, content_id: String(contentRow.Id) };

// Merge brand data if brand_id exists
const brandIdVal = contentRow.brand_id;
if (brandIdVal && brandsId) {
  try {
    const brandResp = await $http.request({
      method: 'GET',
      url: `${baseUrl}/api/v2/meta/bases/${baseId}/tables/${brandsId}/records`,
      headers: { 'xc-token': token },
      qs: { where: `(Id,eq,${brandIdVal})`, limit: 1 }
    });
    const brandRow = (brandResp.list || [])[0];
    if (brandRow) {
      result.brand_tone = brandRow.tone || '';
      result.brand_name = brandRow.name || '';
      result.brand_palette = brandRow.palette || '';
      result.brand_typography = brandRow.typography || '';
    }
  } catch (e) {
    console.error('Failed to fetch brand data:', e.message);
  }
}

return [{ json: result }];
